-- F1 Regulations Engine — DEMO SEED (idempotent).
-- Illustrative, paraphrased sample data + real ONNX embeddings, so the app
-- works immediately after `docker-compose up` without ingesting any PDFs.
-- NOT official FIA text. Run: make seed   (or: psql < seed.sql). Safe to re-run.
BEGIN;
DELETE FROM documents WHERE id BETWEEN 9001 AND 9003;  -- cascades to articles + embeddings
UPDATE articles a SET parent_id=p.id FROM articles p WHERE a.parent_code=p.article_code AND a.year=p.year AND a.section=p.section AND a.issue=p.issue AND a.id BETWEEN 900001 AND 900100;
COMMIT;
