INSERT INTO documents (id,name,year,section,issue,file_path) VALUES (9001,'DEMO Technical Regulations 2026',2026,'Technical',1,'demo://seed');
INSERT INTO documents (id,name,year,section,issue,file_path) VALUES (9002,'DEMO Sporting Regulations 2026',2026,'Sporting',1,'demo://seed');
INSERT INTO documents (id,name,year,section,issue,file_path) VALUES (9003,'DEMO Financial Regulations 2026',2026,'Financial',1,'demo://seed');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900001,9001,'4',NULL,1,'Mass','Defines the minimum mass of the car and how it is measured.',2026,'Technical',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900002,9001,'4.1','4',2,'Minimum mass','Sample: the car, without fuel, must not weigh less than the season''s minimum mass at any time during a competition.',2026,'Technical',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900003,9001,'4.2','4',2,'Mass distribution','Sample: limits are placed on how the car''s mass may be distributed between the front and rear axles.',2026,'Technical',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900004,9001,'3',NULL,1,'Aerodynamic components','General requirements for bodywork and aerodynamic surfaces.',2026,'Technical',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900005,9001,'3.9','3',2,'Rear wing','Sample: the rear wing geometry must remain within the defined legality volume and may include a moveable element.',2026,'Technical',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900006,9001,'5',NULL,1,'Power unit','Defines the power unit and its permitted energy systems.',2026,'Technical',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900007,9001,'5.2','5',2,'Energy store','Sample: the energy that may be stored and deployed by the electrical systems per lap is capped.',2026,'Technical',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900008,9001,'5.13','5',2,'Fuel','Sample: only fuel meeting the published chemical composition and sustainability criteria may be used.',2026,'Technical',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900009,9001,'11',NULL,1,'Brakes','Requirements for the braking system.',2026,'Technical',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900010,9001,'11.1','11',2,'Brake circuits','Sample: the braking system must use at least two separate hydraulic circuits operated by a single pedal.',2026,'Technical',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900011,9002,'28',NULL,1,'Power unit components','Rules on the number of power unit elements a driver may use.',2026,'Sporting',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900012,9002,'28.2','28',2,'Component allocation','Sample: each driver is allotted a fixed number of each power unit element for the championship season.',2026,'Sporting',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900013,9002,'28.3','28',2,'Grid penalties','Sample: using more than the allotted number of a power unit element incurs a grid place penalty.',2026,'Sporting',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900014,9002,'39',NULL,1,'Safety car','Procedures governing deployment of the safety car.',2026,'Sporting',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900015,9002,'39.1','39',2,'Deployment','Sample: the safety car may be deployed to neutralise a race when competitors or officials are in danger.',2026,'Sporting',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900016,9002,'40',NULL,1,'Parc fermé','Conditions under which cars are held in parc fermé.',2026,'Sporting',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900017,9002,'40.1','40',2,'Restrictions','Sample: once cars enter parc fermé, only a limited list of operations may be carried out on them.',2026,'Sporting',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900018,9002,'6',NULL,1,'Championship points','How championship points are awarded.',2026,'Sporting',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900019,9002,'6.1','6',2,'Points system','Sample: points are awarded to the highest-placed finishers on a published sliding scale.',2026,'Sporting',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900020,9002,'55',NULL,1,'Pit lane','Rules governing conduct in the pit lane.',2026,'Sporting',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900021,9002,'55.1','55',2,'Speed limit','Sample: a pit lane speed limit applies during all track sessions and is enforced electronically.',2026,'Sporting',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900022,9003,'D1',NULL,1,'Cost cap','Defines the cost cap framework for competitors.',2026,'Financial',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900023,9003,'D1.1','D1',2,'Scope','Sample: the cost cap limits the total relevant costs a team may incur within a reporting period.',2026,'Financial',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900024,9003,'D4',NULL,1,'Cost cap amount','The applicable cost cap figure.',2026,'Financial',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900025,9003,'D4.1','D4',2,'Cap value','Sample: the cost cap is set at a published amount per full season, adjusted for the number of races.',2026,'Financial',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900026,9003,'D5',NULL,1,'Excluded costs','Costs that fall outside the cost cap.',2026,'Financial',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900027,9003,'D5.1','D5',2,'Exclusions','Sample: marketing, driver salaries and certain employee costs are excluded from relevant costs.',2026,'Financial',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900028,9003,'D8',NULL,1,'Reporting','Financial reporting obligations of competitors.',2026,'Financial',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900029,9003,'D8.1','D8',2,'Submissions','Sample: teams must submit interim and full-year reporting documentation by the published deadlines.',2026,'Financial',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900030,9003,'D12',NULL,1,'Breach','Consequences of breaching the financial regulations.',2026,'Financial',1,false,'ok');
INSERT INTO articles (id,document_id,article_code,parent_code,level,title,content,year,section,issue,is_stub,structural_status) VALUES (900031,9003,'D12.1','D12',2,'Sanctions','Sample: breaches may result in financial penalties and sporting sanctions depending on severity.',2026,'Financial',1,false,'ok');
